dashboard.definition:
{
	"dataSources": {
		"ds_FR6UFDVB": {
			"type": "ds.search",
			"options": {
				"query": "`n8n_index` sourcetype::n8n:json eventName IN ($workflow_event_types$) $search_filter$ \n| rex mode=sed \"s/^n8n\\.workflow\\.//g\" field=eventName \n| table _time, eventName, payload.workflowName, payload.executionId, payload.isManual\n| rename payload.* AS * \n| rename eventName as Event, _time as Time workflowName AS Workflow \n| sort - Time \n| convert ctime(Time) timeformat=\"%Y-%m-%d %H:%M:%S\"",
				"queryParameters": {
					"sampleRatio": 1,
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "recent_workflow_activity"
		},
		"ds_VvotyBPa": {
			"type": "ds.search",
			"options": {
				"query": "`n8n_index` sourcetype::n8n:json eventName IN (n8n.workflow.started) \n| stats count"
			},
			"name": "recent_started_workflows"
		},
		"ds_PH4CSRiz": {
			"type": "ds.search",
			"options": {
				"query": "`n8n_index` sourcetype::n8n:json eventName IN (n8n.workflow.success) \n| stats count"
			},
			"name": "recent_successful_workflows"
		},
		"ds_gi5mliBc": {
			"type": "ds.search",
			"options": {
				"query": "`n8n_index` sourcetype::n8n:json eventName IN (n8n.workflow.failed) \n| stats count"
			},
			"name": "recent_failed_workflows"
		},
		"ds_Dj2le5gv": {
			"type": "ds.search",
			"options": {
				"query": "`n8n_index` sourcetype::n8n:json eventName IN (\"n8n.workflow.started\", \"n8n.workflow.success\", \"n8n.workflow.failed\") \"payload.isManual\"=false \n| stats max(_time) as end, min(_time) as start by payload.executionId \n| eval duration=end-start\n| stats avg(duration) as avg_duration \n| eval avg_duration = round(avg_duration,2)"
			},
			"name": "workflow_duration"
		}
	},
	"visualizations": {
		"viz_utvcufnS": {
			"type": "splunk.table",
			"options": {
				"dataOverlayMode": "none",
				"drilldown": "none",
				"showRowNumbers": false,
				"showInternalFields": false,
				"columnFormat": {
					"Event": {
						"data": "> table | seriesByName(\"Event\") | formatByType(EventColumnFormatEditorConfig)",
						"align": "auto",
						"headerAlign": "auto",
						"textOverflow": "break-word",
						"rowColors": "> table | seriesByName(\"Event\") | matchValue(EventRowColorsEditorConfig)"
					}
				}
			},
			"context": {
				"EventColumnColorConfig": [
					{
						"match": ".*deleted.*",
						"value": "#0099E0"
					}
				],
				"EventColumnFormatEditorConfig": {
					"string": {
						"unitPosition": "after"
					}
				},
				"EventRowColorsEditorConfig": [
					{
						"match": "*failed*",
						"value": "#a81a45"
					}
				]
			},
			"dataSources": {
				"primary": "ds_FR6UFDVB"
			},
			"title": "Recent workflow activity"
		},
		"viz_VkrBI4kp": {
			"type": "splunk.singlevalue",
			"dataSources": {
				"primary": "ds_VvotyBPa"
			},
			"title": "Started workflows",
			"options": {
				"majorColor": "#0877a6"
			}
		},
		"viz_p4gWcSoV": {
			"type": "splunk.singlevalue",
			"dataSources": {
				"primary": "ds_PH4CSRiz"
			},
			"title": "Successful workflows",
			"options": {
				"majorColor": "#53a051"
			}
		},
		"viz_iUoEkcne": {
			"type": "splunk.singlevalue",
			"dataSources": {
				"primary": "ds_gi5mliBc"
			},
			"title": "Failed workflows",
			"options": {
				"majorColor": "#dc4e41"
			}
		},
		"viz_UIOkushP": {
			"type": "splunk.singlevalue",
			"dataSources": {
				"primary": "ds_Dj2le5gv"
			},
			"title": "Workflow duration (avg)",
			"options": {
				"majorColor": "#b6c75a",
				"unit": "s",
				"numberPrecision": 1
			}
		}
	},
	"applicationProperties": {
		"hideEdit": false,
		"hideExport": false
	},
	"inputs": {
		"input_global_trp": {
			"type": "input.timerange",
			"options": {
				"token": "global_time",
				"defaultValue": "-24h@h,now"
			},
			"title": "Time"
		},
		"input_SL1WsPQ0": {
			"options": {
				"items": [
					{
						"label": "All",
						"value": "n8n.workflow.*"
					},
					{
						"label": "Started",
						"value": "n8n.workflow.started"
					},
					{
						"label": "Success",
						"value": "n8n.workflow.success"
					},
					{
						"label": "Failed",
						"value": "n8n.workflow.failed"
					}
				],
				"token": "workflow_event_types",
				"selectFirstSearchResult": true
			},
			"title": "Events",
			"type": "input.dropdown"
		},
		"input_nMa5li8u": {
			"options": {
				"defaultValue": "*",
				"token": "search_filter"
			},
			"title": "Search",
			"type": "input.text"
		}
	},
	"layout": {
		"options": {},
		"globalInputs": [
			"input_global_trp",
			"input_SL1WsPQ0",
			"input_nMa5li8u"
		],
		"tabs": {
			"items": [
				{
					"layoutId": "layout_1",
					"label": "New tab"
				}
			]
		},
		"layoutDefinitions": {
			"layout_1": {
				"type": "grid",
				"structure": [
					{
						"item": "viz_VkrBI4kp",
						"type": "block",
						"position": {
							"x": 0,
							"y": 0,
							"w": 354,
							"h": 156
						}
					},
					{
						"item": "viz_utvcufnS",
						"type": "block",
						"position": {
							"x": 0,
							"y": 156,
							"w": 1440,
							"h": 459
						}
					},
					{
						"item": "viz_p4gWcSoV",
						"type": "block",
						"position": {
							"x": 354,
							"y": 0,
							"w": 355,
							"h": 156
						}
					},
					{
						"item": "viz_iUoEkcne",
						"type": "block",
						"position": {
							"x": 709,
							"y": 0,
							"w": 365,
							"h": 156
						}
					},
					{
						"item": "viz_UIOkushP",
						"type": "block",
						"position": {
							"x": 1074,
							"y": 0,
							"w": 366,
							"h": 156
						}
					}
				],
				"options": {
					"width": 1440,
					"height": 960
				}
			}
		}
	},
	"title": "Operations",
	"description": "",
	"defaults": {
		"dataSources": {
			"ds.search": {
				"options": {
					"queryParameters": {
						"latest": "$global_time.latest$",
						"earliest": "$global_time.earliest$"
					}
				}
			}
		},
		"visualizations": {
			"global": {
				"showProgressBar": true
			}
		}
	}
}
